# AWS Lambda function code using Python 3.x
import json
import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError
from PIL import Image, ExifTags
import logging
from io import BytesIO
import sys
sys.path.insert(0,'/var/task')

# IAM Role definition with broad permissions for AWS services involved in the function: S3, SNS, CloudWatch Logs
iam_role = {
    "Version": "2012-10-17",
    "Statement": [{
        "Effect": "Allow",
        "Action": [
            "s3:GetObject",
            "s3:PutObject",
            "sns:Publish",
            "logs:CreateLogGroup",
            "logs:CreateLogStream",
            "logs:PutLogEvents"
        ],
        "Resource": "*"
    }]
}

# Initializing logging to CloudWatch Logs
logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    try:
        # Create S3 resource using boto3 library
        s3 = boto3.resource('s3')
        
        # Bucket and object details from the event data
        bucket = event['Records'][0]['s3']['bucket']['name']
        key = event['Records'][0]['s3']['object']['key'] 
        
        # Get the image object from S3
        img_obj = s3.Object(bucket, key)
        file_stream = BytesIO()
        img_obj.download_fileobj(file_stream)
        
        # Load Image and rotate if it has EXIF metadata 
        img = Image.open(file_stream)
        try:
            for orientation in ExifTags.TAGS.keys():
                if ExifTags.TAGS[orientation] == 'Orientation':
                    break
            exif=dict(img._getexif().items())
            
            if exif[orientation] == 3:
                img=img.rotate(180, expand=True)
            elif exif[orientation] == 6:
                img=img.rotate(270, expand=True)
            elif exif[orientation] == 8:
                img=img.rotake(90, expand=True)
        
        except (AttributeError, TypeError, KeyError):
            # Skip if no EXIF data found or it's not a JPEG file 
            pass
          
        # Save the edited image back to S3 with an unique filename  
        new_key = "edited-" + key
        img.save('/tmp/temp.jpg')
        
        s3.meta.client.upload_file('/tmp/temp.jpg', bucket, new_key)
        
        # Publish notification via SNS 
        sns = boto3.client('sns')
        topic_arn = 'arn:aws:sns:REGION:ACCOUNT_ID:SNS_TOPIC'
        message = "Image processing completed for image with key {}".format(key)
        
        response = sns.publish(TopicArn=topic_arn, Message=message)
    
    except (NoCredentialsError, PartialCredentialsError):
        logger.error('Missing AWS Credentials')
            
    except Exception as e:
        logger.error("Unexpected error: %s", str(e))